import { decodeEventLog, parseAbi } from "viem";

async function main() {
  const log = {
    topics: [
      '0x8c5261668696ce22758910d05bab8f186d6eb247ceac2af2e82c7dc17669b036'
    ],
    data: '' as `0x${string}`
  };

  const MESSAGE_TRANSMITTER_ABI = parseAbi([
    'event MessageSent(bytes message)',
    'function receiveMessage(bytes message, bytes attestation) returns (bool)',
  ]);

  try {
    console.log("Attempting decodeEventLog with MESSAGE_TRANSMITTER_ABI (containing function)...");
    const decoded = decodeEventLog({
      abi: MESSAGE_TRANSMITTER_ABI,
      data: log.data,
      topics: log.topics as any
    });
    console.log("Decoded successfully using MESSAGE_TRANSMITTER_ABI:", decoded.eventName, decoded.args);
  } catch (err: any) {
    console.error("decodeEventLog with MESSAGE_TRANSMITTER_ABI failed:", err.message);
  }
}

main().catch(console.error);
